SELECT COUNT(*) AS quantidade_participacoes FROM lattes_p_banca pb JOIN lattes_banca b ON pb.fk_banca = b.pk JOIN servidor s ON pb.fk_siape = s.pk_siape WHERE s.genero = 'FEMININO' AND LOWER(s.sigla_campus) = LOWER('itu') AND LOWER(s.area_ingresso) = LOWER('psicologia') AND (LOWER(b.natureza) LIKE LOWER('%aperfeicoamento%') OR LOWER(b.natureza) LIKE LOWER('%aperfeicoamento%') OR LOWER(b.natureza) LIKE LOWER('%especializa%c%')) AND b.ano >= CAST(strftime('%Y', 'now') AS INTEGER) - 5